package com.hospital.management.controller.billing;import com.hospital.management.dao.*;import com.hospital.management.dao.impl.*;import com.hospital.management.model.*;import com.hospital.management.service.*;import com.hospital.management.service.impl.BillServiceImpl;import javax.servlet.*;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import java.io.*;import java.util.*;@WebServlet("/billing/create")public class BillCreateServlet extends HttpServlet{private final BillService service;private final AppointmentDao appointments;private final DoctorDao doctors;public BillCreateServlet(){this(new BillServiceImpl(),new AppointmentDaoImpl(),new DoctorDaoImpl());}public BillCreateServlet(BillService s,AppointmentDao a,DoctorDao d){service=s;appointments=a;doctors=d;}protected void doGet(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{BillForm f=new BillForm();Long id=BillingRequest.id(q.getParameter("appointmentId"));f.setAppointmentId(id);f.setTaxAmount("0.00");f.setDiscountAmount("0.00");BillItemForm i=new BillItemForm();i.setItemType("OTHER");i.setQuantity("1");i.setUnitPrice("0.00");try{if(id!=null){Appointment a=appointments.findById(id).orElse(null);if(a==null){r.sendError(404);return;}f.setPatientId(a.getPatientId());i.setItemType("CONSULTATION");i.setDescription("Consultation charge");Doctor d=doctors.findById(a.getDoctorId()).orElse(null);i.setUnitPrice(d==null||d.getConsultationFee()==null?"0.00":d.getConsultationFee().toString());q.setAttribute("appointment",a);}}catch(Exception e){r.sendError(500);return;}f.setItems(List.of(i));show(q,r,f);}protected void doPost(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{BillForm f=BillingRequest.bill(q);ServiceResult<Long>x=service.createBill(f,BillingRequest.audit(q),BillingRequest.user(q));if(x.isSuccess()){r.sendRedirect(q.getContextPath()+"/billing/view?id="+x.getData());return;}q.setAttribute("errors",x.getErrors());q.setAttribute("errorMessage",x.getMessage());show(q,r,f);}private void show(HttpServletRequest q,HttpServletResponse r,BillForm f)throws ServletException,IOException{q.setAttribute("billForm",f);q.setAttribute("formMode","CREATE");q.getRequestDispatcher("/WEB-INF/views/billing/form.jsp").forward(q,r);}}
